arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable, and
        // direct SQL queries referencing c.Discriminator keep working.
        configurationBuilder.Conventions.Remove(
            typeof(Microsoft.EntityFrameworkCore.Cosmos.Metadata.Conventions.CosmosDiscriminatorConvention));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Restore EF8-era discriminator property name for backward compatibility.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // EF Core 9 changed the id format from "EntityType|Key" to just "Key".
            // Use a value generator / shadow-property override to keep the old format
            // so existing documents (id = "Product|123") are still found.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<ProductIdGenerator>();
        });

        // HasIndex() was removed from the Cosmos provider in EF Core 9 — it now
        // throws at model building time.  Cosmos indexing is managed via indexing
        // policy on the container, not through EF.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

// Generates id values matching the EF Core 8 "Product|{key}" format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    // EF Core 9 Cosmos provider removed all synchronous APIs (ToList, First, etc.).
    // Every query must be async now.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" as
        // the discriminator property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync .ToList() is no longer supported; use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

