using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 changed the JSON discriminator property from "Discriminator"
            // to "$type".  Existing 500K documents use "Discriminator", and our direct
            // SQL queries (c.Discriminator) depend on it.  Explicitly restore the old name.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — Id synthesis format changed.
            // EF Core 8 synthesized the Cosmos "id" as "EntityType|Key" (e.g. "Product|123").
            // EF Core 9 uses just the key value ("123").  Existing documents still have the
            // old format.  We add an explicit string property mapped to the JSON "id" and
            // generate values in the legacy format so reads/writes stay compatible.
            entity.Property(p => p.CosmosId)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws.
            // The Cosmos provider no longer pretends to support indexes via EF.
            // Manage indexing policy on the container directly in Azure.
            // (The old HasIndex(p => p.Sku) call has been removed.)
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }

    // Explicit Cosmos document id — preserves EF Core 8 "Product|{key}" format.
    public string CosmosId { get; set; }
}

/// <summary>
/// Generates id values in the EF Core 8 legacy format: "Product|{key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

